// filtrar_followups
const data = $input.first().json;
const all = [...(data.agora || []), ...(data.hoje || []), ...(data.podeEsperar || [])];
function isFollowup(a) {
  return a._requiresFollowup === true || a._requiresFollowup === 'true';
}
const followups = all.filter(isFollowup);
const nonFollowups = all.filter(a => !isFollowup(a));
return [{ json: { followups, nonFollowups, original: data } }];

// build_response — branch WITH follow-up messages

const mergeData = $items('merge_and_prioritize')[0].json;
// se no seu canvas não existir "merge_and_prioritize1", troque pelo nome EXATO do node

const followupResults = $input.all().map(i => i.json);

const followupMap = {};
for (const f of followupResults) {
  if (f.id) {
    followupMap[String(f.id)] = f.mensagem_pronta || '';
  }
}

function buildAction(action) {
  const out = {
    id: action.id,
    tipo: action.tipo,
    action_type: action.action_type,
    titulo: action.titulo,
    motivo: (action.motivo || []).slice(0, 3),
    impacto: action.impacto,
    risco: action.risco,
    tempo_estimado: action.tempo_estimado,
    acao_recomendada: action.acao_recomendada,
    next_best_action: action.next_best_action,
  };

  if (action.tipo === 'pipeline') {
    out.parceiro = action.parceiro;
  }

  if (followupMap[String(action.id)]) {
    out.mensagem_pronta = followupMap[String(action.id)];
  }

  return out;
}

const response = {
  status: 'ok',
  resumo: {
    agora: mergeData.agora.length,
    hoje: mergeData.hoje.length,
    podeEsperar: mergeData.podeEsperar.length,
    total_agora_original: mergeData.total_agora_original,
    total_hoje_original: mergeData.total_hoje_original,
    total_podeEsperar_original: mergeData.total_podeEsperar_original,
  },
  agora: (mergeData.agora || []).map(buildAction),
  hoje: (mergeData.hoje || []).map(buildAction),
  podeEsperar: (mergeData.podeEsperar || []).map(buildAction),
};

return [{ json: response }];

const tarefasRaw = $input.first().json?.response || [];
const pipelineRaw = $('consultar_pipeline').first()?.json?.response || [];

// =====================
// NORMALIZAR TAREFAS
// =====================
const tarefas = tarefasRaw
  .filter(t => {
    const status = (t.status_norm || '').toLowerCase();
    return status !== 'concluido' && status !== 'feito';
  })
  .map(t => ({
    ...t,
    tipo: 'tarefa'
  }));

// =====================
// NORMALIZAR PIPELINE
// =====================
const pipeline = pipelineRaw
  .filter(p => {
    const status = (p.status_norm || '').toLowerCase();
    return status !== 'fechamento' && status !== 'ganho' && status !== 'perdido';
  })
  .map(p => ({
    ...p,
    tipo: 'pipeline'
  }));

// =====================
// OUTPUT
// =====================
return [
  {
    json: {
      tarefas,
      pipeline
    }
  }
];

const input = $input.first().json;

const pipeline = input.pipeline || [];

const SLA = {
  'aguardando proposta': 7,
  'compliance': 3,
  'minuta com cliente': 7,
  'juridico': 10,
  'fechamento': 3,
};

function scorePipeline(item) {
  let score = 0;
  const motivo = [];

  const status = (item.status_norm || '').toLowerCase();

  // peso por status
  if (SLA[status]) {
    score += SLA[status];
    motivo.push(`SLA ${status}`);
  }

  // dias parado
  if (item.data_inicio_status) {
    const inicio = new Date(item.data_inicio_status.split('/').reverse().join('-'));
    const hoje = new Date();
    const dias = Math.floor((hoje - inicio) / (1000 * 60 * 60 * 24));

    score += dias;

    if (dias > 5) {
      motivo.push(`${dias} dias parado`);
    }
  }

  return {
    ...item,
    score,
    motivo
  };
}

// 🔥 IMPORTANTE: aqui estava quebrando antes
const pipelineScored = pipeline.map(scorePipeline);

return [
  {
    json: {
      pipeline: pipelineScored,
      tarefas: input.tarefas || []
    }
  }
];

// score_tasks
const input = $input.first().json;

const tarefas = input.tarefas || [];
const pipeline = input.pipeline || [];

function calcularDiasRestantes(prazo) {
  if (!prazo) return null;

  const hoje = new Date();
  const data = new Date(prazo.split('/').reverse().join('-'));

  return Math.floor((data - hoje) / (1000 * 60 * 60 * 24));
}

function scoreTarefa(item) {
  let score = 0;
  const motivo = [];
  let risco = 'baixo';

  const daysUntilDue = calcularDiasRestantes(item.prazo);
  const status = (item.status_norm || '').toLowerCase();

  // 🔥 PRIORIDADE POR PRAZO
  if (daysUntilDue !== null && daysUntilDue < 0) {
    score += 5;
    risco = 'alto';
    motivo.push(`Tarefa vencida há ${Math.abs(daysUntilDue)} dia(s)`);
  } else if (daysUntilDue === 0) {
    score += 4;
    risco = 'medio';
    motivo.push('Tarefa vence hoje');
  } else if (daysUntilDue !== null && daysUntilDue <= 2) {
    score += 3;
    risco = 'medio';
    motivo.push(`Vence em ${daysUntilDue} dia(s)`);
  }

  // 🔥 PRIORIDADE POR STATUS
  if (['em andamento', 'in progress', 'in_progress'].includes(status)) {
    score += 2;
    motivo.push('Tarefa em andamento');
  } else if (['pendente', 'pending'].includes(status)) {
    score += 1;
    motivo.push('Tarefa pendente');
  }

  return {
    ...item,
    score,
    motivo,
    risco
  };
}

const scoredTarefas = tarefas.map(scoreTarefa);

return [
  {
    json: {
      pipeline,
      tarefas: scoredTarefas
    }
  }
];

// merge_and_prioritize
const { pipeline, tarefas } = $input.first().json;

const SLA = {
  'aguardando proposta': 7,
  'compliance': 3,
  'minuta com cliente': 7,
  'juridico': 10,
  'fechamento': 3,
};

function getBucket(score) {
  if (score >= 6) return 'agora';
  if (score >= 3) return 'hoje';
  return 'podeEsperar';
}

function getImpacto(score) {
  if (score >= 8) return 'alto';
  if (score >= 4) return 'medio';
  return 'baixo';
}

function needsFollowup(item) {
  const sf = item.status_followup_norm;
  const daysSince = item._days_since_followup;
  if (sf === 'late' || sf === 'atrasado') return true;
  if (sf === 'pending' || sf === 'pendente') return true;
  if (daysSince === null) return true;
  if (daysSince >= 3) return true;
  return false;
}

function getPipelineRisco(item) {
  const sla = SLA[item.status_norm] || null;
  const daysInStatus = item._days_in_status;
  if (sla !== null && daysInStatus !== null) {
    if (daysInStatus > sla + 7) return 'alto';
    if (daysInStatus > sla) return 'medio';
  }
  return 'baixo';
}

function getNextBestAction(tipo, action_type, status_norm, bucket) {
  const urgencia = bucket === 'agora' ? 'alta' : bucket === 'hoje' ? 'media' : 'baixa';
  if (tipo === 'tarefa') {
    return { tipo: 'execucao', canal: 'crm', objetivo: 'executar tarefa', urgencia };
  }
  if (action_type === 'check_pipeline') {
    return { tipo: 'analise', canal: 'crm', objetivo: 'revisar negociacao', urgencia };
  }
  const objetivoMap = {
    'aguardando proposta': 'destravar proposta',
    'compliance': 'acelerar compliance',
    'juridico': 'cobrar devolutiva juridica',
    'fechamento': 'avancar fechamento',
  };
  const objetivo = objetivoMap[status_norm] || 'avancar negociacao';
  return { tipo: 'followup', canal: 'whatsapp', objetivo, urgencia };
}

const actions = [];

for (const item of pipeline) {
  const risco = getPipelineRisco(item);
  let boostedScore = item.score;
  if (risco === 'alto') boostedScore += 3;
  else if (risco === 'medio') boostedScore += 1;

  const bucket = getBucket(boostedScore);
  const impacto = getImpacto(boostedScore);
  const requiresFollowup = needsFollowup(item);
  const action_type = requiresFollowup ? 'followup' : 'check_pipeline';
  const next_best_action = getNextBestAction('pipeline', action_type, item.status_norm, bucket);

  const contato = item.ponto_focal || item.parceiro || 'responsável';

  const titulo = action_type === 'followup'
    ? `Follow-up: ${item.parceiro} — ${item.produto}`
    : `Analisar negociação: ${item.parceiro} — ${item.produto}`;

  const acao_recomendada = action_type === 'followup'
    ? `Enviar follow-up para ${contato} sobre ${item.produto}`
    : `Verificar andamento da negociação com ${item.parceiro}`;

  const tempo_estimado = action_type === 'followup' ? '2 min' : '5 min';

  const action = {
    id: item.id_followup,
    tipo: 'pipeline',
    action_type,
    parceiro: item.parceiro,
    titulo,
    motivo: item.motivo,
    impacto,
    risco,
    bucket,
    score: boostedScore,
    tempo_estimado,
    acao_recomendada,
    next_best_action,
    _requiresFollowup: requiresFollowup,
    _raw: item,
  };

  actions.push(action);
}

for (const item of tarefas) {
  const bucket = getBucket(item.score);
  const impacto = getImpacto(item.score);
  const risco = item.risco || 'baixo';
  const next_best_action = getNextBestAction('tarefa', 'execucao', null, bucket);
  const daysUntilDue = item._days_until_due;
  const tempo_estimado = (daysUntilDue !== null && daysUntilDue <= 0) ? '10 min' : '5 min';

  const action = {
    id: item.id,
    tipo: 'tarefa',
    action_type: 'execucao',
    titulo: item.titulo,
    motivo: item.motivo,
    impacto,
    risco,
    bucket,
    score: item.score,
    tempo_estimado,
    acao_recomendada: `Executar tarefa: ${item.titulo}`,
    next_best_action,
    _requiresFollowup: false,
    _raw: item,
  };

  actions.push(action);
}

actions.sort((a, b) => b.score - a.score);

const agoraAll = actions.filter(a => a.bucket === 'agora');
const hojeAll = actions.filter(a => a.bucket === 'hoje');
const podeEsperarAll = actions.filter(a => a.bucket === 'podeEsperar');

const agora = agoraAll.slice(0, 5);
const hoje = hojeAll.slice(0, 10);
const podeEsperar = podeEsperarAll.slice(0, 10);

const has_followup_actions = actions.some(a => a._requiresFollowup);

return [{ json: {
  actions,
  agora,
  hoje,
  podeEsperar,
  has_followup_actions,
  total_agora_original: agoraAll.length,
  total_hoje_original: hojeAll.length,
  total_podeEsperar_original: podeEsperarAll.length,
} }];
